select result.student_id , result.student_name , result.subject_name , count(Examinations.student_id) as attended_exams  from (select * from Students cross join Subjects ) as result left outer join Examinations on (result.student_id = Examinations.student_id) and (result.subject_name = Examinations.subject_name) group by result.student_id , result.student_name , result.subject_name order by result.student_id ASC , result.student_name ASC
